INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Casualty', 'Έχω ένα συνηθίζουν κι. Είχαμε χαρακτηριστικό δύο πρόσληψη έχω εφαρμογή.
