INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('1110744109', 'Inpatient Department (IPD)');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Anesthesiology', 'Ίδιο ήδη πλέον δύο. Γραφικά σωστά δεν έλεγχος ώρα κανένας ο. Γέλασαν οι έξι αν αυτός. Επί κόψεις άρα προσλάμβανες λετπά.
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('1703989821', 'Gastroenterology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Cardiology', 'Αρέσει περισσότερη στη εργαλείων σημαντικό. Επί μάλλον ρωτήσει έξι συνάδελφος. Δυστυχώς καλύτερο πηγαίου νέο έτσι από. Μαγικά επί προγραμματιστές.', '189', '1', 'Κτήριο Τουλούπη', '2703607563');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2703607563', 'Neurology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('ENT', 'Εγώ εκτός κάτι. Ναι ως ότι χρειάζονται. Νέου απομόνωση σε πάντως διορθώσεις.
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2201843741', 'Opthalmology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Geriatric', 'Απαραίτητο πιο δοκιμάσεις. Κόλπα πολύ εκείνου σημαντικό. Έτσι έστελνε περισσότερες μιας γραμμή δείξει. Περιεχόμενα των εφαρμογής πρώτο βρίσκονται προγραμματιστής ρουτίνα.', '98', '9', 'Κτήριο Γκικόπουλος', '2204867811');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2204867811', 'Urology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Gastroenterology', 'Ας πάντα ταξινομεί μέχρι. Αθόρυβες δοκιμάσεις πλέον πετάνε υποψήφιο μαγικά συνέχεια.
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('3008699800', 'Gastroenterology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('General surgery', 'Ρωτάει πετάνε διαχειριστής. Μα βιβλίο στο κώδικάς.
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2107822657', 'Geriatric');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Gynaecology', 'Πλέον απλό προβληματική περιβάλλοντος δυστυχής στα. Όσο βάζοντας μιας διαδίκτυο. Διάσημα βγήκε χρονοδιαγράμματα όχι διαπιστώνεις. Ότι τη τρέξει περισσότερη διαδίκτυο.', '30', '6', 'Κτήριο Φιλίππου', '2804832401');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2804832401', 'Outpatient Department (OPD)');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Haematology', 'Σε πετάξαμε κόψεις περισσότερες περισσότερες. Μετρήσεις προκαλείς ατόμου. Περισσότερη διευθυντές πες. Απαρατήρητο θέμα κοιτάζοντας διαπιστώνεις στη τι.', '138', '10', 'Κτήριο Καραντζόπουλος', '0702712050');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('0702712050', 'Operating theatre (OT)');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Pediatrics', 'Πολύ μέχρι αποστηθίσει καταλάθος να επί του. Ας με διακοπής μεταγλωτιστής παραδοτέου σε. Με σπίτι εργαζόμενοι στραβά εκθέσεις αποκλειστικούς.', '82', '4', 'Κτήριο Γκαλίου', '2102592416');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2102592416', 'Outpatient Department (OPD)');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Neurology', 'Διασφαλίζεται χρόνου κι μάλλον πάρα έρθει. Βγήκε δεν γραμμές χρησιμοποιώντας τύπους. Πετάνε απίστευτα υποψήφιο όταν εργαζόμενων χώρου. Προσοχή επιχείριση προσθέσει έλεγχος.', '128', '-1', 'Κτήριο Καρατάσου', '2804994670');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2804994670', 'Geriatric');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Oncology', 'Αθόρυβες τις πάντα έστειλε. Κλπ τρέξει και περιμένουν αυτήν μεταγλωτίσει εδώ. Για ιδιαίτερα περιμένουν ας περιβάλλον οι ποσοστό.
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('1205712514', 'Neurology');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Opthalmology', 'Διοικητικό διοικητικό υψηλότερη επεξεργασία παραπάνω. Σου ξέχασε σίγουρος έστελνε ελέγχου γέλασαν κανείς. Ωραίο σκεφτείς σαν περιμένουν ποσοστό όχι μάλλον.', '98', '6', 'Κτήριο Μαντζώρος', '2803774844');
INSERT INTO doctor_dept (AMKA, dept_name) VALUES ('2803774844', 'Pediatrics');
INSERT INTO department (dept_name, description, number_of_beds, floor, building, director_id) VALUES ('Orthopaedic', 'Εικόνες αρχεία στα φίλος εξακολουθεί έτσι. Λοιπόν στις πάρεις. Δοκιμάσεις εκδόσεις χρησιμοποιώντας ναι είχαμε στραβά.
